export type MessagesResolveData = {
    body: {
        /**
         * The task resolution data. The latest message in the active chat fork must be an assistant message blocked on the matching task type.
         */
        task: {
            type: 'confirmed-steps';
            /**
             * Names of integrations that were successfully connected (e.g. "Neon", "Supabase"). Pass an empty array to skip.
             */
            connectedIntegrationNames?: Array<string>;
            /**
             * Names of MCP presets that were connected (e.g. "Linear", "Sentry"). Pass an empty array to skip.
             */
            connectedMcpPresetNames?: Array<'Linear' | 'Notion' | 'Context7' | 'Sentry' | 'Zapier' | 'Glean' | 'Hex' | 'Sanity' | 'Granola' | 'PostHog' | 'Contentful' | 'Slack'>;
            /**
             * Names of scripts that were applied.
             */
            appliedScripts?: Array<string>;
            /**
             * Names of environment variables that were added.
             */
            addedEnvVars?: Array<string>;
        } | {
            type: 'plan-exit-response';
            /**
             * Whether the plan is approved, rejected, or needs changes.
             */
            status: 'approved' | 'rejected' | 'request-changes';
            /**
             * Feedback or instructions for the agent.
             */
            content: string;
        } | {
            type: 'answered-questions';
            /**
             * Answers to the questions the agent asked.
             */
            answers: Array<{
                /**
                 * The ID of the question being answered.
                 */
                questionId: string;
                /**
                 * The text of the question being answered.
                 */
                questionText: string;
                /**
                 * The labels of the selected options. For single-select questions, pass one item.
                 */
                selectedLabels: Array<string>;
                /**
                 * Free-form text input, used when the user selects "Other" or wants to add context.
                 */
                customText?: string;
            }>;
        } | {
            type: 'confirmed-permissions';
            /**
             * The permissions to grant. Pass the suggestedPermissions from the stopped task.
             */
            permissions: Array<{
                type: 'ALLOW_DYNAMIC_TOOL_STRICT';
                /**
                 * The name of the tool being permitted.
                 */
                toolName: string;
                /**
                 * The tool call input arguments. Pass the exact input from the stopped task.
                 */
                input: unknown;
                /**
                 * Label shown while the tool is running (e.g. "Running migration").
                 */
                taskNameActive?: string | null;
                /**
                 * Label shown after the tool completes (e.g. "Migration complete").
                 */
                taskNameComplete?: string | null;
                /**
                 * Optional message from the user about this permission.
                 */
                userMessage?: string;
            }>;
            /**
             * Optional message from the user about the permission grant.
             */
            userMessage?: string;
        };
        /**
         * Overrides for the model behavior.
         */
        modelConfiguration?: {
            /**
             * Model to use for the generation. `v0-auto` is deprecated and falls back to `v0-pro`.
             */
            modelId?: 'v0-auto' | 'v0-mini' | 'v0-pro' | 'v0-max' | 'v0-max-fast';
            /**
             * Enables image generations to generate up to 5 images per version.
             */
            imageGenerations?: boolean;
        };
    };
    path: {
        /**
         * The unique identifier of the chat.
         */
        chatId: string;
    };
    query?: never;
    url: '/api/v2/chats/{chatId}/messages/resolve';
};

